  display: flex;
  justify-content: space-between;
}

.detail-item strong {
  color: #6b7280;
  font-weight: 500;
}

.detail-tips {
  padding: 0.5rem;
  background: #eff6ff;
  border-radius: 0.25rem;
  font-size: 0.75rem;
