  margin-bottom: 0.125rem;
}

.airline-name, .hotel-name {
  font-weight: 600;
  font-size: 0.8rem;
  color: #1f2937;
}

.price, .rating {
  font-weight: 600;
  font-size: 0.75rem;
  color: #059669;
}

.route-info, .location-info {
  font-size: 0.7rem;
