  .travel-content {
    padding: 0;
    gap: 0.75rem;
  }

  .itinerary-items {
    flex-direction: column;
    gap: 0.5rem;
  }

  .agent-indicators {
    flex-direction: column;
    gap: 0.5rem;
  }

  .agent-indicator {
    padding: 0.75rem;
  }

  .travel-details {
    padding: 0.75rem;
  }

  .interrupt-container {
    padding: 0.5rem;
  }

  .option-card {
    padding: 0.625rem;
  }

  .interrupt-options {
    max-height: 250px;
  }
}

