mastra-agent-local::human_in_the_loop.content:
"use client";
import React, { useState, useEffect } from "react";
import "@copilotkit/react-core/v2/styles.css";
import { 
  useHumanInTheLoop,
  useConfigureSuggestions,
  CopilotChat,
  CopilotChatConfigurationProvider,
} from "@copilotkit/react-core/v2";
import { CopilotKit,
useLangGraphInterrupt } from "@copilotkit/react-core";
import { z } from "zod";
import { useTheme } from "next-themes";

interface HumanInTheLoopProps {
  params: Promise<{
    integrationId: string;
  }>;
}

const HumanInTheLoop: React.FC<HumanInTheLoopProps> = ({ params }) => {
  const { integrationId } = React.use(params);

  return (
    <CopilotKit
      runtimeUrl={`/api/copilotkit/${integrationId}`}
      showDevConsole={false}
      agent="human_in_the_loop"
    >
      <Chat integrationId={integrationId} />
    </CopilotKit>
  );
};

interface Step {
  description: string;
  status: "disabled" | "enabled" | "executing";
}

// Shared UI Components
const StepContainer = ({ theme, children }: { theme?: string; children: React.ReactNode }) => (
  <div data-testid="select-steps" className="flex">
    <div
      className={`relative rounded-xl w-[600px] p-6 shadow-lg backdrop-blur-sm ${
        theme === "dark"
          ? "bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 text-white border border-slate-700/50 shadow-2xl"
          : "bg-gradient-to-br from-white via-gray-50 to-white text-gray-800 border border-gray-200/80"
      }`}
    >
      {children}
    </div>
  </div>
);

const StepHeader = ({
  theme,
  enabledCount,
  totalCount,
  status,
  showStatus = false,
}: {
  theme?: string;
  enabledCount: number;
  totalCount: number;
  status?: string;
  showStatus?: boolean;
}) => (
  <div className="mb-5">
    <div className="flex items-center justify-between mb-3">
      <h2 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
        Select Steps
      </h2>
      <div className="flex items-center gap-3">
        <div className={`text-sm ${theme === "dark" ? "text-slate-400" : "text-gray-500"}`}>
          {enabledCount}/{totalCount} Selected
        </div>
        {showStatus && (
          <div
            className={`text-xs px-2 py-1 rounded-full font-medium ${
              status === "executing"
                ? theme === "dark"
                  ? "bg-blue-900/30 text-blue-300 border border-blue-500/30"
                  : "bg-blue-50 text-blue-600 border border-blue-200"
                : theme === "dark"
                  ? "bg-slate-700 text-slate-300"
                  : "bg-gray-100 text-gray-600"
            }`}
          >
            {status === "executing" ? "Ready" : "Waiting"}
          </div>
        )}
      </div>
    </div>

    <div
      className={`relative h-2 rounded-full overflow-hidden ${theme === "dark" ? "bg-slate-700" : "bg-gray-200"}`}
    >
      <div
        className="absolute top-0 left-0 h-full bg-gradient-to-r from-blue-500 to-purple-500 rounded-full transition-all duration-500 ease-out"
        style={{ width: `${totalCount > 0 ? (enabledCount / totalCount) * 100 : 0}%` }}
      />
    </div>
  </div>
);

const StepItem = ({
  step,
  theme,
  status,
  onToggle,
  disabled = false,
}: {
  step: { description: string; status: string };
  theme?: string;
  status?: string;
  onToggle: () => void;
  disabled?: boolean;
}) => (
  <div
    className={`flex items-center p-3 rounded-lg transition-all duration-300 ${
      step.status === "enabled"
        ? theme === "dark"
          ? "bg-gradient-to-r from-blue-900/20 to-purple-900/10 border border-blue-500/30"
          : "bg-gradient-to-r from-blue-50 to-purple-50 border border-blue-200/60"
        : theme === "dark"
          ? "bg-slate-800/30 border border-slate-600/30"
          : "bg-gray-50/50 border border-gray-200/40"
    }`}
  >
    <label data-testid="step-item" className="flex items-center cursor-pointer w-full">
      <div className="relative">
        <input
          type="checkbox"
          checked={step.status === "enabled"}
          onChange={onToggle}
          className="sr-only"
          disabled={disabled}
        />
        <div
          className={`w-5 h-5 rounded border-2 flex items-center justify-center transition-all duration-200 ${
            step.status === "enabled"
              ? "bg-gradient-to-br from-blue-500 to-purple-600 border-blue-500"
              : theme === "dark"
                ? "border-slate-400 bg-slate-700"
                : "border-gray-300 bg-white"
          } ${disabled ? "opacity-60" : ""}`}
        >
          {step.status === "enabled" && (
            <svg
              className="w-3 h-3 text-white"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={3}
                d="M5 13l4 4L19 7"
              />
            </svg>
          )}
        </div>
      </div>
      <span
        data-testid="step-text"
        className={`ml-3 font-medium transition-all duration-300 ${
          step.status !== "enabled" && status != "inProgress"
            ? `line-through ${theme === "dark" ? "text-slate-500" : "text-gray-400"}`
            : theme === "dark"
              ? "text-white"
              : "text-gray-800"
        } ${disabled ? "opacity-60" : ""}`}
      >
        {step.description}
      </span>
    </label>
  </div>
);

const ActionButton = ({
  variant,
  theme,
  disabled,
  onClick,
  children,
}: {
  variant: "primary" | "secondary" | "success" | "danger";
  theme?: string;
  disabled?: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) => {
  const baseClasses = "px-6 py-3 rounded-lg font-semibold transition-all duration-200";
  const enabledClasses = "hover:scale-105 shadow-md hover:shadow-lg";
  const disabledClasses = "opacity-50 cursor-not-allowed";

  const variantClasses = {
    primary:
      "bg-gradient-to-r from-purple-500 to-purple-700 hover:from-purple-600 hover:to-purple-800 text-white shadow-lg hover:shadow-xl",
    secondary:
      theme === "dark"
        ? "bg-slate-700 hover:bg-slate-600 text-white border border-slate-600 hover:border-slate-500"
        : "bg-gray-100 hover:bg-gray-200 text-gray-800 border border-gray-300 hover:border-gray-400",
    success:
      "bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 text-white shadow-lg hover:shadow-xl",
    danger:
      "bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 text-white shadow-lg hover:shadow-xl",
  };

  return (
    <button
      className={`${baseClasses} ${disabled ? disabledClasses : enabledClasses} ${
        disabled && variant === "secondary"
          ? "bg-gray-200 text-gray-500"
          : disabled && variant === "success"
            ? "bg-gray-400"
            : variantClasses[variant]
      }`}
      disabled={disabled}
      onClick={onClick}
    >
      {children}
    </button>
  );
};

const DecorativeElements = ({
  theme,
  variant = "default",
}: {
  theme?: string;
  variant?: "default" | "success" | "danger";
}) => (
  <>
    <div
      className={`absolute top-3 right-3 w-16 h-16 rounded-full blur-xl ${
        variant === "success"
          ? theme === "dark"
            ? "bg-gradient-to-br from-green-500/10 to-emerald-500/10"
            : "bg-gradient-to-br from-green-200/30 to-emerald-200/30"
          : variant === "danger"
            ? theme === "dark"
              ? "bg-gradient-to-br from-red-500/10 to-pink-500/10"
              : "bg-gradient-to-br from-red-200/30 to-pink-200/30"
            : theme === "dark"
              ? "bg-gradient-to-br from-blue-500/10 to-purple-500/10"
              : "bg-gradient-to-br from-blue-200/30 to-purple-200/30"
      }`}
    />
    <div
      className={`absolute bottom-3 left-3 w-12 h-12 rounded-full blur-xl ${
        variant === "default"
          ? theme === "dark"
            ? "bg-gradient-to-br from-purple-500/10 to-pink-500/10"
            : "bg-gradient-to-br from-purple-200/30 to-pink-200/30"
          : "opacity-50"
      }`}
    />
  </>
);
const InterruptHumanInTheLoop: React.FC<{
  event: { value: { steps: Step[] } };
  resolve: (value: string) => void;
}> = ({ event, resolve }) => {
  const { theme } = useTheme();

  // Parse and initialize steps data
  let initialSteps: Step[] = [];
  if (event.value && event.value.steps && Array.isArray(event.value.steps)) {
    initialSteps = event.value.steps.map((step: any) => ({
      description: typeof step === "string" ? step : step.description || "",
      status: typeof step === "object" && step.status ? step.status : "enabled",
    }));
  }

  const [localSteps, setLocalSteps] = useState<Step[]>(initialSteps);
  const enabledCount = localSteps.filter((step) => step.status === "enabled").length;

  const handleStepToggle = (index: number) => {
    setLocalSteps((prevSteps) =>
      prevSteps.map((step, i) =>
        i === index
          ? { ...step, status: step.status === "enabled" ? "disabled" : "enabled" }
          : step,
      ),
    );
  };

  const handlePerformSteps = () => {
    const selectedSteps = localSteps
      .filter((step) => step.status === "enabled")
      .map((step) => step.description);
    resolve("The user selected the following steps: " + selectedSteps.join(", "));
  };

  return (
    <StepContainer theme={theme}>
      <StepHeader theme={theme} enabledCount={enabledCount} totalCount={localSteps.length} />

      <div className="space-y-3 mb-6">
        {localSteps.map((step, index) => (
          <StepItem
            key={index}
            step={step}
            theme={theme}
            onToggle={() => handleStepToggle(index)}
          />
        ))}
      </div>

      <div className="flex justify-center">
        <ActionButton variant="primary" theme={theme} onClick={handlePerformSteps}>
          <span className="text-lg">✨</span>
          Perform Steps
          <span
            className={`ml-1 px-2 py-1 rounded-full text-xs font-bold ${
              theme === "dark" ? "bg-purple-800/50" : "bg-purple-600/20"
            }`}
          >
            {enabledCount}
          </span>
        </ActionButton>
      </div>

      <DecorativeElements theme={theme} />
    </StepContainer>
  );
};

const Chat = ({ integrationId }: { integrationId: string }) => {
  return (
    <CopilotChatConfigurationProvider agentId="human_in_the_loop">
      <ChatContent />
    </CopilotChatConfigurationProvider>
  );
};

const ChatContent = () => {
  useConfigureSuggestions({
    suggestions: [
      { title: "Simple plan", message: "Please plan a trip to mars in 5 steps." },
      { title: "Complex plan", message: "Please plan a pasta dish in 10 steps." },
    ],
    available: "always",
  });

  // Langgraph uses it's own hook to handle human-in-the-loop interactions via langgraph interrupts,
  // This hook won't do anything for other integrations.
  useLangGraphInterrupt({

    render: ({ event, resolve }) => <InterruptHumanInTheLoop event={event} resolve={resolve} />,
  });
  useHumanInTheLoop({
    agentId: "human_in_the_loop",
    name: "generate_task_steps",
    description: "Generates a list of steps for the user to perform",
     parameters: z.object({
      steps: z.array(
        z.object({
          description: z.string(),
          status: z.enum(["enabled", "disabled", "executing"]),
        }),
      ),
    })  ,
    // Note: In v1, `available` was used to disable this for langgraph integrations.
    // In v2, availability is handled at the agent/backend level.
    render: ({ args, respond, status }: any) => {
      return <StepsFeedback args={args} respond={respond} status={status} />;
    },
  });

  return (
    <div className="flex justify-center items-center h-full w-full">
      <div className="h-full w-full md:w-8/10 md:h-8/10 rounded-lg">
        <CopilotChat
          agentId="human_in_the_loop"
          className="h-full rounded-2xl max-w-6xl mx-auto"
        />
      </div>
    </div>
  );
};

const StepsFeedback = ({ args, respond, status }: { args: any; respond: any; status: any }) => {
  const { theme } = useTheme();
  const [localSteps, setLocalSteps] = useState<Step[]>([]);
  const [accepted, setAccepted] = useState<boolean | null>(null);

  useEffect(() => {
    if (status === "executing" && localSteps.length === 0 && Array.isArray(args?.steps) && args.steps.length > 0) {
      setLocalSteps(args.steps);
    }
  }, [status, args?.steps, localSteps]);

  if (!Array.isArray(args?.steps) || args.steps.length === 0) {
    return <></>;
  }

  const steps = Array.isArray(localSteps) && localSteps.length > 0 ? localSteps : args.steps;
  const enabledCount = steps.filter((step: any) => step.status === "enabled").length;

  const handleStepToggle = (index: number) => {
    setLocalSteps((prevSteps) =>
      prevSteps.map((step, i) =>
        i === index
          ? { ...step, status: step.status === "enabled" ? "disabled" : "enabled" }
          : step,
      ),
    );
  };

  const handleReject = () => {
    if (respond) {
      setAccepted(false);
      respond({ accepted: false });
    }
  };

  const handleConfirm = () => {
    if (respond) {
      const confirmedSteps = localSteps.filter((step) => step.status === "enabled");
      setAccepted(true);
      respond({ accepted: true, steps: confirmedSteps });
    }
  };

  return (
    <StepContainer theme={theme}>
      <StepHeader
        theme={theme}
        enabledCount={enabledCount}
        totalCount={steps.length}
        status={status}
        showStatus={true}
      />

      <div className="space-y-3 mb-6">
        {steps.map((step: any, index: any) => (
          <StepItem
            key={index}
            step={step}
            theme={theme}
            status={status}
            onToggle={() => handleStepToggle(index)}
            disabled={status !== "executing"}
          />
        ))}
      </div>

      {/* Action Buttons - Different logic from InterruptHumanInTheLoop */}
      {accepted === null && (
        <div className="flex justify-center gap-4">
          <ActionButton
            variant="secondary"
            theme={theme}
            disabled={status !== "executing"}
            onClick={handleReject}
          >
            <span className="mr-2">✗</span>
            Reject
          </ActionButton>
          <ActionButton
            variant="success"
            theme={theme}
            disabled={status !== "executing"}
            onClick={handleConfirm}
          >
            <span className="mr-2">✓</span>
            Confirm
            <span
              className={`ml-2 px-2 py-1 rounded-full text-xs font-bold ${
                theme === "dark" ? "bg-green-800/50" : "bg-green-600/20"
              }`}
            >
              {enabledCount}
            </span>
          </ActionButton>
        </div>
      )}

      {/* Result State - Unique to StepsFeedback */}
      {accepted !== null && (
        <div className="flex justify-center">
          <div
            className={`px-6 py-3 rounded-lg font-semibold flex items-center gap-2 ${
              accepted
                ? theme === "dark"
                  ? "bg-green-900/30 text-green-300 border border-green-500/30"
                  : "bg-green-50 text-green-700 border border-green-200"
                : theme === "dark"
                  ? "bg-red-900/30 text-red-300 border border-red-500/30"
                  : "bg-red-50 text-red-700 border border-red-200"
            }`}
          >
            <span className="text-lg">{accepted ? "✓" : "✗"}</span>
            {accepted ? "Accepted" : "Rejected"}
          </div>
        </div>
      )}

      <DecorativeElements
        theme={theme}
        variant={accepted === true ? "success" : accepted === false ? "danger" : "default"}
      />
    </StepContainer>
  );
};

export default HumanInTheLoop;

import { Agent } from "@mastra/core/agent";
import { Memory } from "@mastra/memory";
import { getStorage } from "../storage";

export const humanInTheLoopAgent = new Agent({
  id: 'human_in_the_loop',
  name: "human_in_the_loop",
  instructions: `
    You are a helpful task planning assistant that helps users break down tasks into actionable steps.

    When planning tasks use tools only, without any other messages.
    IMPORTANT:
    - Use the \`generate_task_steps\` tool to display the suggested steps to the user
    - Do not call the \`generate_task_steps\` twice in a row, ever.
    - Never repeat the plan, or send a message detailing steps
    - If accepted, confirm the creation of the plan and the number of selected (enabled) steps only
    - If not accepted, ask the user for more information, DO NOT use the \`generate_task_steps\` tool again

    When responding to user requests:
    - Always break down the task into clear, actionable steps
    - Use imperative form for each step (e.g., "Book flight", "Pack luggage", "Check passport")
    - Keep steps concise but descriptive
    - Make sure steps are in logical order
  `,
  model: "openai/gpt-4.1-mini",
  memory: new Memory({
    storage: getStorage(),
  }),
});

mastra-agent-local::interrupt.content:
"use client";
import React, { useMemo, useState } from "react";
import "@copilotkit/react-core/v2/styles.css";
import {
  CopilotChat,
  CopilotChatConfigurationProvider,
  useConfigureSuggestions,
  useInterrupt,
} from "@copilotkit/react-core/v2";
import { CopilotKit } from "@copilotkit/react-core";
import { useTheme } from "next-themes";

interface InterruptProps {
  params: Promise<{ integrationId: string }>;
}

// Payload the Mastra `schedule_meeting` tool sends via `suspend(...)`. The
// @ag-ui/mastra bridge wraps it in the on_interrupt CUSTOM event under
// `suspendPayload` (the Mastra contract — it carries `toolName`/`toolCallId`/
// `runId` the LangGraph raw-value shape doesn't). We read `suspendPayload`.
interface SuspendPayload {
  topic?: string;
  attendee?: string;
}

interface TimeSlot {
  iso: string;
  label: string;
}

// Generate a few future slots relative to "now" so the picker is always valid.
function generateSlots(): TimeSlot[] {
  const slots: TimeSlot[] = [];
  const now = new Date();
  for (let day = 1; day <= 2; day++) {
    for (const hour of [10, 14]) {
      const d = new Date(now);
      d.setDate(now.getDate() + day);
      d.setHours(hour, 0, 0, 0);
      slots.push({
        iso: d.toISOString(),
        label: d.toLocaleString(undefined, {
          weekday: "short",
          month: "short",
          day: "numeric",
          hour: "numeric",
          minute: "2-digit",
        }),
      });
    }
  }
  return slots;
}

const Interrupt: React.FC<InterruptProps> = ({ params }) => {
  const { integrationId } = React.use(params);

  return (
    <CopilotKit
      runtimeUrl={`/api/copilotkit/${integrationId}`}
      showDevConsole={false}
      agent="interrupt"
    >
      <CopilotChatConfigurationProvider agentId="interrupt">
        <ChatContent />
      </CopilotChatConfigurationProvider>
    </CopilotKit>
  );
};

const ChatContent = () => {
  useConfigureSuggestions({
    suggestions: [
      {
        title: "Book a call with sales",
        message: "Book an intro call with the sales team to discuss pricing.",
      },
      {
        title: "Schedule a 1:1 with Alice",
        message: "Schedule a 1:1 with Alice next week to review Q2 goals.",
      },
    ],
    available: "always",
  });

  // Native interrupt handling. The Mastra agent suspends its `schedule_meeting`
  // tool; the bridge emits `on_interrupt`; this renders the picker and
  // `resolve(...)` resumes the suspended tool with the user's choice.
  useInterrupt({
    agentId: "interrupt",
    renderInChat: true,
    render: ({ event, resolve }) => {
      // The adapter JSON-stringifies the interrupt value, so parse it.
      const raw = event.value ?? {};
      const parsed = (typeof raw === "string" ? JSON.parse(raw) : raw) as {
        suspendPayload?: SuspendPayload;
      };
      const payload = parsed.suspendPayload ?? {};
      return (
        <TimePickerCard
          topic={payload.topic ?? "a call"}
          attendee={payload.attendee}
          onPick={(slot) =>
            resolve({ chosen_time: slot.iso, chosen_label: slot.label })
          }
          onCancel={() => resolve({ cancelled: true })}
        />
      );
    },
  });

  return (
    <div className="flex justify-center items-center h-full w-full">
      <div className="h-full w-full md:w-8/10 md:h-8/10 rounded-lg">
        <CopilotChat
          agentId="interrupt"
          className="h-full rounded-2xl max-w-6xl mx-auto"
        />
      </div>
    </div>
  );
};

const TimePickerCard: React.FC<{
  topic: string;
  attendee?: string;
  onPick: (slot: TimeSlot) => void;
  onCancel: () => void;
}> = ({ topic, attendee, onPick, onCancel }) => {
  const { theme } = useTheme();
  const slots = useMemo(() => generateSlots(), []);
  const [done, setDone] = useState<TimeSlot | "cancelled" | null>(null);

  const dark = theme === "dark";

  // Once the user picks/cancels, render nothing: `resolve()` resumes the run and
  // this interrupt render unmounts moments later, with the agent's text taking
  // over as the confirmation. Blanking on click (rather than leaving the slots
  // up) gives an instant, clean handoff and prevents a double-pick. We don't
  // show a "Booked" card here — it would only flash before unmounting; the
  // agent's message is the record.
  if (done) {
    return null;
  }

  return (
    <div
      data-testid="interrupt-picker"
      className={`rounded-xl w-[480px] p-6 shadow-lg ${
        dark
          ? "bg-slate-800 text-white border border-slate-700"
          : "bg-white text-gray-800 border border-gray-200"
      }`}
    >
      <h2 className="text-lg font-semibold mb-1">{topic}</h2>
      {attendee ? (
        <p className="text-sm opacity-70 mb-4">with {attendee}</p>
      ) : (
        <div className="mb-4" />
      )}

      <div className="grid grid-cols-2 gap-2">
        {slots.map((slot) => (
          <button
            key={slot.iso}
            type="button"
            data-testid={`interrupt-slot-${slot.iso}`}
            onClick={() => {
              setDone(slot);
              onPick(slot);
            }}
            className={`rounded-lg border px-3 py-3 text-sm font-medium transition-colors ${
              dark
                ? "border-slate-600 hover:border-blue-400 hover:bg-slate-700"
                : "border-gray-200 hover:border-blue-400 hover:bg-blue-50"
            }`}
          >
            {slot.label}
          </button>
        ))}
      </div>

      <button
        type="button"
        data-testid="interrupt-cancel"
        onClick={() => {
          setDone("cancelled");
          onCancel();
        }}
        className={`mt-4 w-full rounded-lg border px-3 py-2 text-xs font-medium uppercase tracking-wide transition-colors ${
          dark
            ? "border-slate-600 hover:bg-slate-700"
            : "border-gray-200 hover:bg-gray-50"
        }`}
      >
        Cancel
      </button>
    </div>
  );
};

export default Interrupt;

import { Agent } from "@mastra/core/agent";
import { Memory } from "@mastra/memory";
import { scheduleMeetingTool } from "../tools";
import { getStorage } from "../storage";

// Demonstrates Mastra's native suspend/resume HITL bridged onto AG-UI's
// `on_interrupt` flow. The agent calls `schedule_meeting`, which suspends; the
// @ag-ui/mastra adapter emits a CUSTOM `on_interrupt` event; CopilotKit's v2
// `useInterrupt` hook renders a time picker and resumes the tool. Resume works
// for both LOCAL and REMOTE Mastra agents (the remote path round-trips the
// resume over @mastra/client-js' resumeStream, OSS-380), so this is wired for
// both `mastra-agent-local` and the remote `mastra` integration.
export const interruptAgent = new Agent({
  id: "interrupt",
  name: "interrupt",
  instructions: `You are a scheduling assistant. Whenever the user asks you to book a call or schedule a meeting, you MUST call the \`schedule_meeting\` tool. Pass a short \`topic\` describing the purpose and, if known, an \`attendee\` describing who the meeting is with.

The \`schedule_meeting\` tool pauses execution and shows the user a time picker. After it resumes with the user's choice, briefly confirm whether the meeting was scheduled and at what time, or note that the user cancelled. Do not ask for approval yourself — always call the tool and let the picker handle the decision. Keep responses short and friendly.`,
  model: "openai/gpt-4.1-mini",
  // Cast: a tool with concrete suspend/resume schemas is not structurally
  // assignable to Mastra's `ToolAction<..., unknown, unknown, ...>` tools map
  // (generic variance). Runtime behavior is unaffected.
  tools: { schedule_meeting: scheduleMeetingTool as any },
  memory: new Memory({
    storage: getStorage(),
  }),
});

import { createTool } from "@mastra/core/tools";
import { z } from "zod";

export const weatherTool = createTool({
  id: "get-weather",
  description: "Get current weather for a location",
  inputSchema: z.object({
    location: z.string().describe("City name"),
  }),
  outputSchema: z.object({
    temperature: z.number(),
    feelsLike: z.number(),
    humidity: z.number(),
    windSpeed: z.number(),
    windGust: z.number(),
    conditions: z.string(),
    city: z.string(),
  }),
  execute: async (inputData) => {
    return await getWeather(inputData.location);
  },
});

// Backend tool that suspends its own execution (Mastra's native HITL
// primitive). When `suspend()` is called the @ag-ui/mastra bridge emits a
// CUSTOM `on_interrupt` event; CopilotKit's v2 `useInterrupt` renders the
// picker and resumes the tool with the user's choice via `resumeData`.
export const scheduleMeetingTool = createTool({
  id: "schedule-meeting",
  description:
    "Ask the user to pick a meeting time. Surfaces an in-chat time picker " +
    "and returns the user's selection so the agent can confirm.",
  inputSchema: z.object({
    topic: z.string().describe("Short description of the meeting purpose"),
    attendee: z.string().optional().describe("Who the meeting is with"),
  }),
  // What the frontend receives on suspend (read by the interrupt renderer).
  suspendSchema: z.object({
    topic: z.string(),
    attendee: z.string().optional(),
  }),
  // What the frontend sends back to resume the tool.
  resumeSchema: z.object({
    chosen_time: z.string().optional(),
    chosen_label: z.string().optional(),
    cancelled: z.boolean().optional(),
  }),
  execute: async (inputData, context) => {
    const { resumeData, suspend } = context?.agent ?? {};

    // First execution: pause and ask the user to pick a time. Return the
    // `suspend()` call directly — it keeps the tool suspended so Mastra pauses
    // the run at `tool-call-suspended`. Do NOT `await` then return a value:
    // that completes the tool and the agent continues without the user.
    if (!resumeData) {
      return suspend?.({
        topic: inputData.topic,
        attendee: inputData.attendee,
      });
    }

    // Resumed: the user has responded.
    if (resumeData.cancelled) {
      return `User cancelled. Meeting NOT scheduled: ${inputData.topic}`;
    }
    const label = resumeData.chosen_label ?? resumeData.chosen_time;
    return label
      ? `Meeting scheduled for ${label}: ${inputData.topic}`
      : `User did not pick a time. Meeting NOT scheduled: ${inputData.topic}`;
  },
});

const getWeather = async (location: string) => {
  return {
    temperature: 20,
    feelsLike: 22,
    humidity: 60,
    windSpeed: 10,
    windGust: 15,
    conditions: "Sunny",
    city: location,
  };
};

mastra-agent-local::shared_state.content:
"use client";
import {
  useAgent,
  UseAgentUpdate,
  useCopilotKit,
  useConfigureSuggestions,
  CopilotChat,
  CopilotSidebar,
} from "@copilotkit/react-core/v2";
import React, { useState, useEffect, useRef } from "react";
import "@copilotkit/react-core/v2/styles.css";
import "./style.css";
import { useMobileView } from "@/utils/use-mobile-view";
import { useMobileChat } from "@/utils/use-mobile-chat";
import { useURLParams } from "@/contexts/url-params-context";
import { CopilotKit } from "@copilotkit/react-core";

interface SharedStateProps {
  params: Promise<{
    integrationId: string;
  }>;
}

export default function SharedState({ params }: SharedStateProps) {
  const { integrationId } = React.use(params);
  const { isMobile } = useMobileView();
  const { chatDefaultOpen } = useURLParams();
  const defaultChatHeight = 50;
  const { isChatOpen, setChatHeight, setIsChatOpen, isDragging, chatHeight, handleDragStart } =
    useMobileChat(defaultChatHeight);

  const chatTitle = "AI Recipe Assistant";
  const chatDescription = "Ask me to craft recipes";

  return (
    <CopilotKit
      runtimeUrl={`/api/copilotkit/${integrationId}`}
      showDevConsole={false}
      agent="shared_state"
    >
      <div className="min-h-screen w-full flex items-center justify-center">
        <Recipe />
        {isMobile ? (
          <>
            {/* Chat Toggle Button */}
            <div className="fixed bottom-0 left-0 right-0 z-50">
              <div className="bg-gradient-to-t from-white via-white to-transparent h-6"></div>
              <div
                className="bg-white border-t border-gray-200 px-4 py-3 flex items-center justify-between cursor-pointer shadow-lg"
                onClick={() => {
                  if (!isChatOpen) {
                    setChatHeight(defaultChatHeight); // Reset to good default when opening
                  }
                  setIsChatOpen(!isChatOpen);
                }}
              >
                <div className="flex items-center gap-3">
                  <div>
                    <div className="font-medium text-gray-900">{chatTitle}</div>
                    <div className="text-sm text-gray-500">{chatDescription}</div>
                  </div>
                </div>
                <div
                  className={`transform transition-transform duration-300 ${isChatOpen ? "rotate-180" : ""}`}
                >
                  <svg
                    className="w-6 h-6 text-gray-400"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M5 15l7-7 7 7"
                    />
                  </svg>
                </div>
              </div>
            </div>

            {/* Pull-Up Chat Container */}
            <div
              className={`fixed inset-x-0 bottom-0 z-40 bg-white rounded-t-2xl shadow-[0px_0px_20px_0px_rgba(0,0,0,0.15)] transform transition-all duration-300 ease-in-out flex flex-col ${
                isChatOpen ? "translate-y-0" : "translate-y-full"
              } ${isDragging ? "transition-none" : ""}`}
              style={{
                height: `${chatHeight}vh`,
                paddingBottom: "env(safe-area-inset-bottom)", // Handle iPhone bottom padding
              }}
            >
              {/* Drag Handle Bar */}
              <div
                className="flex justify-center pt-3 pb-2 flex-shrink-0 cursor-grab active:cursor-grabbing"
                onMouseDown={handleDragStart}
              >
                <div className="w-12 h-1 bg-gray-400 rounded-full hover:bg-gray-500 transition-colors"></div>
              </div>

              {/* Chat Header */}
              <div className="px-4 py-3 border-b border-gray-100 flex-shrink-0">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <h3 className="font-semibold text-gray-900">{chatTitle}</h3>
                  </div>
                  <button
                    onClick={() => setIsChatOpen(false)}
                    className="p-2 hover:bg-gray-100 rounded-full transition-colors"
                  >
                    <svg
                      className="w-5 h-5 text-gray-500"
                      fill="none"
                      stroke="currentColor"
                      viewBox="0 0 24 24"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M6 18L18 6M6 6l12 12"
                      />
                    </svg>
                  </button>
                </div>
              </div>

              {/* Chat Content - Flexible container for messages and input */}
              <div className="flex-1 flex flex-col min-h-0 overflow-hidden pb-16">
                <CopilotChat
                  agentId="shared_state"
                  className="h-full flex flex-col"
                />
              </div>
            </div>

            {/* Backdrop */}
            {isChatOpen && (
              <div className="fixed inset-0 z-30" onClick={() => setIsChatOpen(false)} />
            )}
          </>
        ) : (
          <CopilotSidebar
            agentId="shared_state"
            defaultOpen={chatDefaultOpen}
            labels={{
              modalHeaderTitle: chatTitle,
            }}
          />
        )}
      </div>
    </CopilotKit>
  );
}

enum SkillLevel {
  BEGINNER = "Beginner",
  INTERMEDIATE = "Intermediate",
  ADVANCED = "Advanced",
}

enum CookingTime {
  FiveMin = "5 min",
  FifteenMin = "15 min",
  ThirtyMin = "30 min",
  FortyFiveMin = "45 min",
  SixtyPlusMin = "60+ min",
}

const cookingTimeValues = [
  { label: CookingTime.FiveMin, value: 0 },
  { label: CookingTime.FifteenMin, value: 1 },
  { label: CookingTime.ThirtyMin, value: 2 },
  { label: CookingTime.FortyFiveMin, value: 3 },
  { label: CookingTime.SixtyPlusMin, value: 4 },
];

enum SpecialPreferences {
  HighProtein = "High Protein",
  LowCarb = "Low Carb",
  Spicy = "Spicy",
  BudgetFriendly = "Budget-Friendly",
  OnePotMeal = "One-Pot Meal",
  Vegetarian = "Vegetarian",
  Vegan = "Vegan",
}

interface Ingredient {
  icon: string;
  name: string;
  amount: string;
}

interface Recipe {
  title: string;
  skill_level: SkillLevel;
  cooking_time: CookingTime;
  special_preferences: string[];
  ingredients: Ingredient[];
  instructions: string[];
}

interface RecipeAgentState {
  recipe: Recipe;
}

const INITIAL_STATE: RecipeAgentState = {
  recipe: {
    title: "Make Your Recipe",
    skill_level: SkillLevel.INTERMEDIATE,
    cooking_time: CookingTime.FortyFiveMin,
    special_preferences: [],
    ingredients: [
      { icon: "🥕", name: "Carrots", amount: "3 large, grated" },
      { icon: "🌾", name: "All-Purpose Flour", amount: "2 cups" },
    ],
    instructions: ["Preheat oven to 350°F (175°C)"],
  },
};

function Recipe() {
  const { isMobile } = useMobileView();
  const { agent } = useAgent({
    agentId: "shared_state",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });
  const { copilotkit } = useCopilotKit();

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Create Italian recipe",
        message: "Create a delicious Italian pasta recipe.",
      },
      {
        title: "Make it healthier",
        message: "Make the recipe healthier with more vegetables.",
      },
      {
        title: "Suggest variations",
        message: "Suggest some creative variations of this recipe.",
      },
    ],
    available: "always",
  });

  const agentState = agent.state as RecipeAgentState | undefined;
  const setAgentState = (s: RecipeAgentState) => agent.setState(s);
  const isLoading = agent.isRunning;

  // Set initial state on mount
  useEffect(() => {
    if (!agentState?.recipe) {
      setAgentState(INITIAL_STATE);
    }
  }, []);

  const [recipe, setRecipe] = useState(INITIAL_STATE.recipe);
  const [editingInstructionIndex, setEditingInstructionIndex] = useState<number | null>(null);
  const newInstructionRef = useRef<HTMLTextAreaElement>(null);

  const updateRecipe = (partialRecipe: Partial<Recipe>) => {
    setAgentState({
      ...(agentState || INITIAL_STATE),
      recipe: {
        ...recipe,
        ...partialRecipe,
      },
    });
    setRecipe({
      ...recipe,
      ...partialRecipe,
    });
  };

  const newRecipeState = { ...recipe };
  const newChangedKeys = [];
  const changedKeysRef = useRef<string[]>([]);

  for (const key in recipe) {
    if (
      agentState &&
      agentState.recipe &&
      (agentState.recipe as any)[key] !== undefined &&
      (agentState.recipe as any)[key] !== null
    ) {
      let agentValue = (agentState.recipe as any)[key];
      const recipeValue = (recipe as any)[key];

      // Check if agentValue is a string and replace \n with actual newlines
      if (typeof agentValue === "string") {
        agentValue = agentValue.replace(/\\n/g, "\n");
      }

      if (JSON.stringify(agentValue) !== JSON.stringify(recipeValue)) {
        (newRecipeState as any)[key] = agentValue;
        newChangedKeys.push(key);
      }
    }
  }

  if (newChangedKeys.length > 0) {
    changedKeysRef.current = newChangedKeys;
  } else if (!isLoading) {
    changedKeysRef.current = [];
  }

  useEffect(() => {
    setRecipe(newRecipeState);
  }, [JSON.stringify(newRecipeState)]);

  const handleTitleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    updateRecipe({
      title: event.target.value,
    });
  };

  const handleSkillLevelChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    updateRecipe({
      skill_level: event.target.value as SkillLevel,
    });
  };

  const handleDietaryChange = (preference: string, checked: boolean) => {
    if (checked) {
      updateRecipe({
        special_preferences: [...recipe.special_preferences, preference],
      });
    } else {
      updateRecipe({
        special_preferences: recipe.special_preferences.filter((p) => p !== preference),
      });
    }
  };

  const handleCookingTimeChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    updateRecipe({
      cooking_time: cookingTimeValues[Number(event.target.value)].label,
    });
  };

  const addIngredient = () => {
    // Pick a random food emoji from our valid list
    updateRecipe({
      ingredients: [...recipe.ingredients, { icon: "🍴", name: "", amount: "" }],
    });
  };

  const updateIngredient = (index: number, field: keyof Ingredient, value: string) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients[index] = {
      ...updatedIngredients[index],
      [field]: value,
    };
    updateRecipe({ ingredients: updatedIngredients });
  };

  const removeIngredient = (index: number) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients.splice(index, 1);
    updateRecipe({ ingredients: updatedIngredients });
  };

  const addInstruction = () => {
    const newIndex = recipe.instructions.length;
    updateRecipe({
      instructions: [...recipe.instructions, ""],
    });
    // Set the new instruction as the editing one
    setEditingInstructionIndex(newIndex);

    // Focus the new instruction after render
    setTimeout(() => {
      const textareas = document.querySelectorAll(".instructions-container textarea");
      const newTextarea = textareas[textareas.length - 1] as HTMLTextAreaElement;
      if (newTextarea) {
        newTextarea.focus();
      }
    }, 50);
  };

  const updateInstruction = (index: number, value: string) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions[index] = value;
    updateRecipe({ instructions: updatedInstructions });
  };

  const removeInstruction = (index: number) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions.splice(index, 1);
    updateRecipe({ instructions: updatedInstructions });
  };

  // Simplified icon handler that defaults to a fork/knife for any problematic icons
  const getProperIcon = (icon: string | undefined): string => {
    // If icon is undefined  return the default
    if (!icon) {
      return "🍴";
    }

    return icon;
  };

  return (
    <form
      data-testid="recipe-card"
      style={isMobile ? { marginBottom: "100px" } : {}}
      className="recipe-card"
    >
      {/* Recipe Title */}
      <div className="recipe-header">
        <input
          type="text"
          value={recipe.title || ""}
          onChange={handleTitleChange}
          className="recipe-title-input"
        />

        <div className="recipe-meta">
          <div className="meta-item">
            <span className="meta-icon">🕒</span>
            <select
              className="meta-select"
              value={cookingTimeValues.find((t) => t.label === recipe.cooking_time)?.value || 3}
              onChange={handleCookingTimeChange}
              style={{
                backgroundImage:
                  "url(\"data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%23555' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e\")",
                backgroundRepeat: "no-repeat",
                backgroundPosition: "right 0px center",
                backgroundSize: "12px",
                appearance: "none",
                WebkitAppearance: "none",
              }}
            >
              {cookingTimeValues.map((time) => (
                <option key={time.value} value={time.value}>
                  {time.label}
                </option>
              ))}
            </select>
          </div>

          <div className="meta-item">
            <span className="meta-icon">🏆</span>
            <select
              className="meta-select"
              value={recipe.skill_level}
              onChange={handleSkillLevelChange}
              style={{
                backgroundImage:
                  "url(\"data:image/svg+xml;charset=UTF-8,%3csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24' fill='none' stroke='%23555' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'%3e%3cpolyline points='6 9 12 15 18 9'%3e%3c/polyline%3e%3c/svg%3e\")",
                backgroundRepeat: "no-repeat",
                backgroundPosition: "right 0px center",
                backgroundSize: "12px",
                appearance: "none",
                WebkitAppearance: "none",
              }}
            >
              {Object.values(SkillLevel).map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Dietary Preferences */}
      <div className="section-container relative">
        {changedKeysRef.current.includes("special_preferences") && <Ping />}
        <h2 className="section-title">Dietary Preferences</h2>
        <div className="dietary-options">
          {Object.values(SpecialPreferences).map((option) => (
            <label key={option} className="dietary-option">
              <input
                type="checkbox"
                checked={recipe.special_preferences.includes(option)}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                  handleDietaryChange(option, e.target.checked)
                }
              />
              <span>{option}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Ingredients */}
      <div className="section-container relative">
        {changedKeysRef.current.includes("ingredients") && <Ping />}
        <div className="section-header">
          <h2 className="section-title">Ingredients</h2>
          <button
            data-testid="add-ingredient-button"
            type="button"
            className="add-button"
            onClick={addIngredient}
          >
            + Add Ingredient
          </button>
        </div>
        <div data-testid="ingredients-container" className="ingredients-container">
          {recipe.ingredients.map((ingredient, index) => (
            <div key={index} data-testid="ingredient-card" className="ingredient-card">
              <div className="ingredient-icon">{getProperIcon(ingredient.icon)}</div>
              <div className="ingredient-content">
                <input
                  type="text"
                  value={ingredient.name || ""}
                  onChange={(e) => updateIngredient(index, "name", e.target.value)}
                  placeholder="Ingredient name"
                  className="ingredient-name-input"
                />
                <input
                  type="text"
                  value={ingredient.amount || ""}
                  onChange={(e) => updateIngredient(index, "amount", e.target.value)}
                  placeholder="Amount"
                  className="ingredient-amount-input"
                />
              </div>
              <button
                type="button"
                className="remove-button"
                onClick={() => removeIngredient(index)}
                aria-label="Remove ingredient"
              >
                ×
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Instructions */}
      <div className="section-container relative">
        {changedKeysRef.current.includes("instructions") && <Ping />}
        <div className="section-header">
          <h2 className="section-title">Instructions</h2>
          <button type="button" className="add-step-button" onClick={addInstruction}>
            + Add Step
          </button>
        </div>
        <div data-testid="instructions-container" className="instructions-container">
          {recipe.instructions.map((instruction, index) => (
            <div key={index} className="instruction-item">
              {/* Number Circle */}
              <div className="instruction-number">{index + 1}</div>

              {/* Vertical Line */}
              {index < recipe.instructions.length - 1 && <div className="instruction-line" />}

              {/* Instruction Content */}
              <div
                className={`instruction-content ${
                  editingInstructionIndex === index
                    ? "instruction-content-editing"
                    : "instruction-content-default"
                }`}
                onClick={() => setEditingInstructionIndex(index)}
              >
                <textarea
                  className="instruction-textarea"
                  value={instruction || ""}
                  onChange={(e) => updateInstruction(index, e.target.value)}
                  placeholder={!instruction ? "Enter cooking instruction..." : ""}
                  onFocus={() => setEditingInstructionIndex(index)}
                  onBlur={(e) => {
                    // Only blur if clicking outside this instruction
                    if (!e.relatedTarget || !e.currentTarget.contains(e.relatedTarget as Node)) {
                      setEditingInstructionIndex(null);
                    }
                  }}
                />

                {/* Delete Button (only visible on hover) */}
                <button
                  type="button"
                  className={`instruction-delete-btn ${
                    editingInstructionIndex === index
                      ? "instruction-delete-btn-editing"
                      : "instruction-delete-btn-default"
                  } remove-button`}
                  onClick={(e) => {
                    e.stopPropagation(); // Prevent triggering parent onClick
                    removeInstruction(index);
                  }}
                  aria-label="Remove instruction"
                >
                  ×
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Improve with AI Button */}
      <div className="action-container">
        <button
          data-testid="improve-button"
          className={isLoading ? "improve-button loading" : "improve-button"}
          type="button"
          onClick={() => {
            if (!isLoading) {
              agent.addMessage({
                id: crypto.randomUUID(),
                role: "user",
                content: "Improve the recipe",
              });
              copilotkit.runAgent({ agent });
            }
          }}
          disabled={isLoading}
        >
          {isLoading ? "Please Wait..." : "Improve with AI"}
        </button>
      </div>
    </form>
  );
}

function Ping() {
  return (
    <span className="ping-animation">
      <span className="ping-circle"></span>
      <span className="ping-dot"></span>
    </span>
  );
}

