        title: "Investigate RAG",
        message:
          "Investigate best practices for retrieval-augmented generation.",
      },
    ],
    available: "always",
  });

  return (
    <CopilotChat
      agentId="background_agents"
      className="h-full rounded-2xl max-w-6xl mx-auto"
    />
  );
