import { Agent } from "@mastra/core/agent";
import { createTool } from "@mastra/core/tools";
import { z } from "zod";

/**
 * Fixed-schema A2UI agent for Mastra (the direct-tool A2UI mode — the sibling of
 * the generate_a2ui/subagent path). The component layout is authored in code
 * (FLIGHT_SCHEMA / HOTEL_SCHEMA); the model only supplies the DATA. Each backend
 * tool returns a complete `a2ui_operations` envelope which the
 * `@ag-ui/a2ui-middleware` detects in the tool result and paints — no subagent,
 * no recovery, no auto-injection. Mirrors the LangGraph/Strands fixed-schema
 * demos; renders against the dojo fixedSchemaCatalog (fixed_catalog.json:
 * Row / FlightCard / HotelCard / StarRating).
 *
 * Return shape: the tool returns the envelope as an OBJECT (not a JSON string) so
 * the Mastra bridge single-encodes it onto the wire and the middleware intercepts
 * it (a bare string would be double-encoded and slip through as a plain result).
 */

const FIXED_CATALOG_ID = "https://a2ui.org/demos/dojo/fixed_catalog.json";
const A2UI_OPERATIONS_KEY = "a2ui_operations";

const FLIGHT_SURFACE_ID = "flight-search-results";
const FLIGHT_SCHEMA: Array<Record<string, unknown>> = [
  {
    id: "root",
    component: "Row",
    children: { componentId: "flight-card", path: "/flights" },
    gap: 16,
  },
  {
    id: "flight-card",
    component: "FlightCard",
    airline: { path: "airline" },
    airlineLogo: { path: "airlineLogo" },
    flightNumber: { path: "flightNumber" },
    origin: { path: "origin" },
    destination: { path: "destination" },
    date: { path: "date" },
    departureTime: { path: "departureTime" },
    arrivalTime: { path: "arrivalTime" },
    duration: { path: "duration" },
    status: { path: "status" },
    price: { path: "price" },
    action: {
      event: {
        name: "book_flight",
        context: {
          flightNumber: { path: "flightNumber" },
          origin: { path: "origin" },
          destination: { path: "destination" },
          price: { path: "price" },
        },
      },
    },
  },
];

const HOTEL_SURFACE_ID = "hotel-search-results";
const HOTEL_SCHEMA: Array<Record<string, unknown>> = [
  {
    id: "root",
    component: "Row",
    children: { componentId: "hotel-card", path: "/hotels" },
    gap: 16,
  },
  {
    id: "hotel-card",
    component: "HotelCard",
    name: { path: "name" },
    location: { path: "location" },
    rating: { path: "rating" },
    pricePerNight: { path: "price" },
    action: {
      event: {
        name: "book_hotel",
        context: {
          hotelName: { path: "name" },
          price: { path: "price" },
        },
      },
    },
  },
];

function renderOperations(
  surfaceId: string,
  schema: Array<Record<string, unknown>>,
  data: Record<string, unknown>,
): { a2ui_operations: Array<Record<string, unknown>> } {
  return {
    [A2UI_OPERATIONS_KEY]: [
      {
        version: "v0.9",
        createSurface: { surfaceId, catalogId: FIXED_CATALOG_ID },
      },
      { version: "v0.9", updateComponents: { surfaceId, components: schema } },
      {
        version: "v0.9",
        updateDataModel: { surfaceId, path: "/", value: data },
      },
    ],
  };
}

const searchFlightsTool = createTool({
  id: "search_flights",
  description:
    "Search for flights and display the results as rich cards. Each flight must " +
    "have: id, airline (e.g. 'United Airlines'), airlineLogo (Google favicon API " +
    "like 'https://www.google.com/s2/favicons?domain=united.com&sz=128'), " +
    "flightNumber, origin, destination, date (e.g. 'Tue, Mar 18'), departureTime, " +
    "arrivalTime, duration (e.g. '4h 25m'), status ('On Time' or 'Delayed'), and " +
    "price (e.g. '$289'). Generate 3-5 realistic results.",
  inputSchema: z.object({
    flights: z
      .array(z.record(z.string(), z.unknown()))
      .describe("Array of flight result objects."),
  }),
  execute: async ({ flights }) =>
    renderOperations(FLIGHT_SURFACE_ID, FLIGHT_SCHEMA, { flights }),
});

const searchHotelsTool = createTool({
  id: "search_hotels",
  description:
    "Search for hotels and display the results as rich cards with star ratings. " +
    "Each hotel must have: id, name (e.g. 'The Plaza'), location " +
    "(e.g. 'Midtown Manhattan, NYC'), rating (float 0-5, e.g. 4.5), and price " +
    "(per night, e.g. '$350'). Generate 3-4 realistic results.",
  inputSchema: z.object({
    hotels: z
      .array(z.record(z.string(), z.unknown()))
      .describe("Array of hotel result objects."),
  }),
  execute: async ({ hotels }) =>
    renderOperations(HOTEL_SURFACE_ID, HOTEL_SCHEMA, { hotels }),
});

export const a2uiFixedSchemaAgent = new Agent({
  id: "a2ui_fixed_schema",
  name: "a2ui_fixed_schema",
  instructions: `You are a helpful travel assistant that can search for flights and hotels.

When the user asks about flights, use the search_flights tool.
When the user asks about hotels, use the search_hotels tool.
IMPORTANT: After calling a tool, do NOT repeat or summarize the data in your text response. The tool renders a rich UI automatically. Just say something brief like "Here are your results".

For flights, each needs: id, airline, airlineLogo (Google favicon API), flightNumber, origin, destination, date, departureTime, arrivalTime, duration, status, and price.
For hotels, each needs: id, name, location, rating (float 0-5), and price (per night).
Generate 3-5 realistic results.`,
  model: "openai/gpt-4.1",
  tools: { search_flights: searchFlightsTool, search_hotels: searchHotelsTool },
});

mastra-agent-local::observational_memory.content:
"use client";
import React from "react";
import "@copilotkit/react-core/v2/styles.css";
import {
  CopilotChat,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { CopilotKit } from "@copilotkit/react-core";
import { z } from "zod";

export const dynamic = "force-dynamic";

// Mirrors the `content` shape the AG-UI Mastra bridge emits for the
// "mastra-observational-memory" activity (see
// MASTRA_OBSERVATIONAL_MEMORY_ACTIVITY_TYPE in @ag-ui/mastra). The bridge builds
// the object up incrementally via a snapshot + JSON-patch deltas, so every
// field beyond the identifiers is optional at render time.
const omContentSchema = z
  .object({
    cycleId: z.string(),
    operationType: z.enum(["observation", "reflection"]).optional(),
    phase: z.enum(["observation", "buffering", "activation"]).optional(),
    status: z.enum(["running", "completed", "failed", "activated"]).optional(),
    threadId: z.string().optional(),
    recordId: z.string().optional(),
    observations: z.string().optional(),
    currentTask: z.string().optional(),
    suggestedResponse: z.string().optional(),
    tokensToObserve: z.number().optional(),
    tokensToBuffer: z.number().optional(),
    tokensObserved: z.number().optional(),
    tokensBuffered: z.number().optional(),
    bufferedTokens: z.number().optional(),
    observationTokens: z.number().optional(),
    tokensActivated: z.number().optional(),
    chunksActivated: z.number().optional(),
    messagesActivated: z.number().optional(),
    generationCount: z.number().optional(),
    triggeredBy: z.enum(["threshold", "ttl", "provider_change"]).optional(),
    durationMs: z.number().optional(),
    startedAt: z.string().optional(),
    completedAt: z.string().optional(),
    error: z.string().optional(),
  })
  .passthrough();

type OmContent = z.infer<typeof omContentSchema>;

const STATUS_STYLES: Record<
  string,
  { dot: string; text: string; label: string }
> = {
  running: { dot: "bg-amber-400", text: "text-amber-700", label: "Working" },
  completed: {
    dot: "bg-emerald-500",
    text: "text-emerald-700",
    label: "Completed",
  },
  activated: {
    dot: "bg-indigo-500",
    text: "text-indigo-700",
    label: "Activated",
  },
  failed: { dot: "bg-rose-500", text: "text-rose-700", label: "Failed" },
};

const PHASE_LABELS: Record<string, string> = {
  observation: "Observing",
  buffering: "Buffering",
  activation: "Activating",
};

function tokens(n?: number): string | null {
  if (typeof n !== "number") return null;
  if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
  return String(n);
}

function ObservationalMemoryCard({ content }: { content: OmContent }) {
  const status = content.status ?? "running";
  const style = STATUS_STYLES[status] ?? STATUS_STYLES.running;
  const isActive = status === "running";
  const phaseLabel = content.phase ? PHASE_LABELS[content.phase] : "Memory";
  const op = content.operationType ?? "observation";

  const observedTokens = content.tokensObserved ?? content.tokensToObserve;
  const resultTokens =
    content.observationTokens ?? content.bufferedTokens ?? undefined;
  const compression =
    typeof observedTokens === "number" &&
    typeof resultTokens === "number" &&
    observedTokens > 0
      ? Math.max(0, 1 - resultTokens / observedTokens)
      : undefined;

  return (
    <div
      data-testid="om-activity-card"
      data-phase={content.phase}
      data-status={status}
      className="my-2 rounded-xl border border-slate-200 bg-gradient-to-br from-indigo-50/60 to-white p-4 shadow-sm max-w-xl"
    >
      <div className="flex items-center justify-between gap-3">
        <div className="flex items-center gap-2">
          <span className="text-[11px] font-semibold uppercase tracking-wider text-slate-400">
            Observational Memory
          </span>
          <code className="rounded bg-slate-100 px-1.5 py-0.5 text-xs font-mono text-slate-600">
            {phaseLabel} · {op}
          </code>
        </div>
        <div className={`flex items-center gap-1.5 ${style.text}`}>
          <span
            className={`h-2 w-2 rounded-full ${style.dot} ${
              isActive ? "animate-pulse" : ""
            }`}
          />
          <span
            className="text-xs font-semibold"
            data-testid="om-activity-status"
          >
            {style.label}
          </span>
        </div>
      </div>

      {content.observations ? (
        <p
          className="mt-2 text-sm text-slate-700"
          data-testid="om-activity-observations"
        >
          {content.observations}
        </p>
      ) : null}

      {content.currentTask ? (
        <p className="mt-2 text-xs text-slate-500">
          <span className="text-slate-400">Task:</span> {content.currentTask}
        </p>
      ) : null}

      <div className="mt-3 flex flex-wrap gap-x-4 gap-y-1 text-xs text-slate-400">
        {tokens(observedTokens) ? (
          <span data-testid="om-activity-observed-tokens">
            Observed {tokens(observedTokens)} tok
          </span>
        ) : null}
        {tokens(resultTokens) ? (
          <span>→ {tokens(resultTokens)} tok</span>
        ) : null}
        {typeof compression === "number" ? (
          <span className="font-medium text-indigo-500">
            {(compression * 100).toFixed(0)}% compressed
          </span>
        ) : null}
        {typeof content.messagesActivated === "number" ? (
          <span>{content.messagesActivated} msgs activated</span>
        ) : null}
        {typeof content.durationMs === "number" ? (
          <span>{(content.durationMs / 1000).toFixed(1)}s</span>
        ) : null}
      </div>

      {isActive ? (
        <div className="mt-3 h-1 w-full overflow-hidden rounded-full bg-slate-100">
          <div className="h-full w-1/3 animate-[shimmer_1.2s_infinite] rounded-full bg-indigo-300" />
        </div>
      ) : null}

      {status === "failed" && content.error ? (
        <p className="mt-3 rounded-lg border border-rose-100 bg-rose-50 p-3 text-sm text-rose-800">
          {content.error}
        </p>
      ) : null}

      <style>{`@keyframes shimmer { 0% { transform: translateX(-120%);} 100% { transform: translateX(320%);} }`}</style>
    </div>
  );
}

const omRenderer = {
  activityType: "mastra-observational-memory",
  content: omContentSchema,
  render: ({ content }: { content: OmContent }) => (
    <ObservationalMemoryCard content={content} />
  ),
};

function Chat() {
  useConfigureSuggestions({
    suggestions: [
      {
        title: "Plan a trip",
        message:
          "I'm planning a two-week trip through Japan in spring. I love food, temples, and trains, and I want to avoid big crowds. Where should I go?",
      },
      {
        title: "Keep chatting",
        message:
          "Tell me more about the food scene there, and remember that I'm vegetarian and don't drink alcohol.",
      },
    ],
    available: "always",
  });

  return (
    <CopilotChat
      agentId="observational_memory"
      className="h-full rounded-2xl max-w-6xl mx-auto"
    />
  );
}

interface PageProps {
  params: Promise<{ integrationId: string }>;
}

export default function Page({ params }: PageProps) {
  const { integrationId } = React.use(params);

  return (
    <CopilotKit
      runtimeUrl={`/api/copilotkit/${integrationId}`}
      showDevConsole={false}
      agent="observational_memory"
      renderActivityMessages={[omRenderer]}
    >
      <div className="flex justify-center items-center h-full w-full">
        <div className="h-full w-full md:w-8/10 md:h-8/10 rounded-lg">
          <Chat />
        </div>
      </div>
    </CopilotKit>
  );
}

spring-ai::agentic_chat.content:
"use client";
import React, { useState } from "react";
import "@copilotkit/react-core/v2/styles.css";
import { 
  useFrontendTool,
  useRenderTool,
  useAgentContext,
  useConfigureSuggestions,
  CopilotChat,
} from "@copilotkit/react-core/v2";
import { z } from "zod";
import { CopilotKit } from "@copilotkit/react-core";

interface AgenticChatProps {
  params: Promise<{
    integrationId: string;
  }>;
}

const AgenticChat: React.FC<AgenticChatProps> = ({ params }) => {
  const { integrationId } = React.use(params);

  return (
    <CopilotKit
      runtimeUrl={`/api/copilotkit/${integrationId}`}
      showDevConsole={false}
      agent="agentic_chat"
    >
      <Chat />
    </CopilotKit>
  );
};

const Chat = () => {
  const [background, setBackground] = useState<string>("--copilot-kit-background-color");

  useAgentContext({
    description: 'Name of the user',
    value: 'Bob'
  });

  useFrontendTool({
    name: "change_background",
    description:
      "Change the background color of the chat. Can be anything that the CSS background attribute accepts. Regular colors, linear of radial gradients etc.",
    parameters: z.object({
      background: z.string().describe("The background. Prefer gradients. Only use when asked."),
    }) ,
    handler: async ({ background }: { background: string }) => {
      setBackground(background);
      return {
        status: "success",
        message: `Background changed to ${background}`,
      };
    },
  });

  useRenderTool({
    name: "get_weather",
    parameters: z.object({
      location: z.string(),
    })  ,
    render: ({ args, result, status }: any) => {
      if (status !== "complete") {
        return <div data-testid="weather-info-loading">Loading weather...</div>;
      }

      // Some integrations (e.g. LangGraph) deliver tool results as a JSON-encoded
      // string in the ToolMessage content rather than a parsed object. Normalize
      // so property access works in either case; otherwise every field reads as
      // undefined and the card renders empty values.
      let parsed: any = result;
      if (typeof parsed === "string") {
        try {
          parsed = JSON.parse(parsed);
        } catch {
          parsed = {};
        }
      }
      parsed = parsed ?? {};

      return (
        <div data-testid="weather-info">
          <strong>Weather in {parsed.city ?? args.location}</strong>
          <div>Temperature: {parsed.temperature}°C</div>
          <div>Humidity: {parsed.humidity}%</div>
          <div>Wind Speed: {parsed.windSpeed ?? parsed.wind_speed} mph</div>
          <div>Conditions: {parsed.conditions}</div>
        </div>
      );
    },
  });

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Change background",
        message: "Change the background to something new.",
      },
      {
        title: "Generate sonnet",
        message: "Write a short sonnet about AI.",
      },
    ],
    available: "always",
  });

  return (
    <div
      className="flex justify-center items-center h-full w-full"
      data-testid="background-container"
      style={{ background }}
    >
      <div className="h-full w-full md:w-8/10 md:h-8/10 rounded-lg">
        <CopilotChat
          agentId="agentic_chat"
          className="h-full rounded-2xl max-w-6xl mx-auto"
        />
      </div>
    </div>
  );
};

export default AgenticChat;

