    public static IChatClient CreatePredictiveStateUpdates()
    {
        // Deliberately NOT wrapped with UseFunctionInvocation: write_document_local is declared
        // so the model calls it, but the call is intercepted by the stream mapping
        // (CreatePredictiveStateUpdatesStreamOptions) — which streams the document into state and
        // injects a confirm_changes tool call — rather than executed server-side. That leaves the
        // run finishing with the confirm_changes call pending for the human-in-the-loop modal.
        return s_chatClient!.AsIChatClient();
    }

    public const string PredictiveStateUpdatesSystemPrompt = """
        You are a document editor assistant. When asked to write or edit content:

        IMPORTANT:
        - Use the `write_document_local` tool with the full document text in Markdown format
        - Format the document extensively so it's easy to read
        - You can use all kinds of markdown (headings, lists, bold, etc.)
        - However, do NOT use italic or strike-through formatting
        - You MUST write the full document, even when changing only a few words
        - When making edits to the document, try to make them minimal - do not change every word
        - Keep stories SHORT!

        After writing the document, briefly summarize the changes you made in at most two sentences.
        """;

    public static IList<AITool> CreatePredictiveStateUpdatesTools(JsonSerializerOptions options)
    {
        return
        [
            AIFunctionFactory.Create(
                WriteDocument,
                name: "write_document_local",
                description: "Write a document. Use markdown formatting to format the document.",
                AGUIDojoServerSerializerContext.Default.Options)
        ];
    }

    public static AGUIStreamOptions CreatePredictiveStateUpdatesStreamOptions(JsonSerializerOptions jsonSerializerOptions)
    {
        string? lastEmittedDocument = null;
        var options = new AGUIStreamOptions();
        options.MapCall("write_document_local", fcc =>
        {
            var documentContent = fcc.Arguments?.TryGetValue("document", out var documentValue) == true
                ? documentValue?.ToString()
                : null;

            if (documentContent is null || documentContent == lastEmittedDocument)
            {
                return [];
            }

            var events = new List<BaseEvent>();
            int startIndex = 0;
            if (lastEmittedDocument is not null && documentContent.StartsWith(lastEmittedDocument, StringComparison.Ordinal))
            {
                startIndex = lastEmittedDocument.Length;
            }

            const int chunkSize = 10;
            for (int i = startIndex; i < documentContent.Length; i += chunkSize)
            {
                int length = Math.Min(chunkSize, documentContent.Length - i);
                string chunk = documentContent.Substring(0, i + length);

                var stateUpdate = new DocumentState { Document = chunk };
                var stateJson = JsonSerializer.SerializeToElement(stateUpdate, jsonSerializerOptions);

                events.Add(new StateSnapshotEvent { Snapshot = stateJson });
            }

            // Complete the write_document_local call (its document is now reflected in the
            // document state) so the only tool call the client sees pending is confirm_changes.
            events.Add(new ToolCallResultEvent
            {
                MessageId = Guid.NewGuid().ToString("N"),
                ToolCallId = fcc.CallId,
                Content = "Document written.",
                Role = "tool",
            });

            // Inject a client-side `confirm_changes` tool call so the dojo human-in-the-loop
            // approval modal renders. This mirrors the crewai predictive_state_updates flow,
            // whose backend appends a synthetic confirm_changes tool call after writing the
            // document — the dojo registers `confirm_changes` via useHumanInTheLoop and shows
            // the confirm/reject modal in response to the call. The call is parented to a fresh
            // assistant message id so the client tracks it correctly across multiple rounds.
            var confirmCallId = Guid.NewGuid().ToString("N");
            var confirmMessageId = Guid.NewGuid().ToString("N");
            events.Add(new ToolCallStartEvent { ToolCallId = confirmCallId, ToolCallName = "confirm_changes", ParentMessageId = confirmMessageId });
            events.Add(new ToolCallArgsEvent { ToolCallId = confirmCallId, Delta = "{}" });
            events.Add(new ToolCallEndEvent { ToolCallId = confirmCallId });

            lastEmittedDocument = documentContent;
            return events;
        });
        return options;
    }

    [Description("Get the weather for a given location.")]
    private static WeatherInfo GetWeather([Description("The location to get the weather for.")] string location) => new()
    {
        Temperature = 20,
        Conditions = "sunny",
        Humidity = 50,
        WindSpeed = 10,
        FeelsLike = 25
    };

    [Description("Write a document in markdown format.")]
    private static string WriteDocument([Description("The document content to write.")] string document)
    {
        // Simply return success - the document is tracked via state updates
        return "Document written successfully";
    }
}

ag-ui-dotnet::tool_based_generative_ui.content:
"use client";
import React, { useState } from "react";
import "@copilotkit/react-core/v2/styles.css";
import { 
  useFrontendTool,
  useConfigureSuggestions,
  CopilotSidebar,
} from "@copilotkit/react-core/v2";
import { z } from "zod";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";
import { useURLParams } from "@/contexts/url-params-context";
import { CopilotKit } from "@copilotkit/react-core";

interface ToolBasedGenerativeUIProps {
  params: Promise<{
    integrationId: string;
  }>;
}

interface Haiku {
  japanese: string[];
  english: string[];
  image_name: string | null;
  gradient: string;
}

export default function ToolBasedGenerativeUI({ params }: ToolBasedGenerativeUIProps) {
  const { integrationId } = React.use(params);
  const { chatDefaultOpen } = useURLParams();

  return (
    <CopilotKit
      runtimeUrl={`/api/copilotkit/${integrationId}`}
      showDevConsole={false}
      agent="tool_based_generative_ui"
    >
      <SidebarWithSuggestions defaultOpen={chatDefaultOpen} />
      <HaikuDisplay />
    </CopilotKit>
  );
}

function SidebarWithSuggestions({ defaultOpen }: { defaultOpen: boolean }) {
  useConfigureSuggestions({
    suggestions: [
      { title: "Nature Haiku", message: "Write me a haiku about nature." },
      { title: "Ocean Haiku", message: "Create a haiku about the ocean." },
      { title: "Spring Haiku", message: "Generate a haiku about spring." },
    ],
    available: "always",
  });

  return (
    <CopilotSidebar
      agentId="tool_based_generative_ui"
      defaultOpen={defaultOpen}
      labels={{
        modalHeaderTitle: "Haiku Generator",
      }}
    />
  );
}

const VALID_IMAGE_NAMES = [
  "Osaka_Castle_Turret_Stone_Wall_Pine_Trees_Daytime.jpg",
  "Tokyo_Skyline_Night_Tokyo_Tower_Mount_Fuji_View.jpg",
  "Itsukushima_Shrine_Miyajima_Floating_Torii_Gate_Sunset_Long_Exposure.jpg",
  "Takachiho_Gorge_Waterfall_River_Lush_Greenery_Japan.jpg",
  "Bonsai_Tree_Potted_Japanese_Art_Green_Foliage.jpeg",
  "Shirakawa-go_Gassho-zukuri_Thatched_Roof_Village_Aerial_View.jpg",
  "Ginkaku-ji_Silver_Pavilion_Kyoto_Japanese_Garden_Pond_Reflection.jpg",
  "Senso-ji_Temple_Asakusa_Cherry_Blossoms_Kimono_Umbrella.jpg",
  "Cherry_Blossoms_Sakura_Night_View_City_Lights_Japan.jpg",
  "Mount_Fuji_Lake_Reflection_Cherry_Blossoms_Sakura_Spring.jpg",
];

function HaikuDisplay() {
  const [activeIndex, setActiveIndex] = useState(0);
  const [haikus, setHaikus] = useState<Haiku[]>([
    {
      japanese: ["仮の句よ", "まっさらながら", "花を呼ぶ"],
      english: ["A placeholder verse—", "even in a blank canvas,", "it beckons flowers."],
      image_name: null,
      gradient: "",
    },
  ]);

  useFrontendTool(
    {
      agentId: "tool_based_generative_ui",
      name: "generate_haiku",
       parameters: z.object({
        japanese: z.array(z.string()).describe("3 lines of haiku in Japanese"),
        english: z.array(z.string()).describe("3 lines of haiku translated to English"),
        image_name: z.string().describe(`One relevant image name from: ${VALID_IMAGE_NAMES.join(", ")}`),
        gradient: z.string().describe("CSS Gradient color for the background"),
      })  ,
      followUp: false,
      handler: async ({ japanese, english, image_name, gradient }: { japanese: string[]; english: string[]; image_name: string; gradient: string }) => {
        const newHaiku: Haiku = {
          japanese: japanese || [],
          english: english || [],
          image_name: image_name || null,
          gradient: gradient || "",
        };
        setHaikus((prev) => [
          newHaiku,
          ...prev.filter((h) => h.english[0] !== "A placeholder verse—"),
        ]);
        setActiveIndex(0);
        return "Haiku generated!";
      },
      render: ({ args }: { args: Partial<Haiku> }) => {
        if (!args.japanese) return <></>;
        return <HaikuCard haiku={args as Haiku} />;
      },
    },
    [haikus],
  );

  const currentHaiku = haikus[activeIndex];

  return (
    <div className="relative flex items-center justify-center h-full w-full">
      <div className="px-20 py-12 w-full max-w-4xl">
        <Carousel className="w-full" data-testid="haiku-carousel">
          <CarouselContent>
            {haikus.map((haiku, index) => (
              <CarouselItem key={index} data-testid={`carousel-item-${index}`}>
                <HaikuCard haiku={haiku} />
              </CarouselItem>
            ))}
          </CarouselContent>
          {haikus.length > 1 && (
            <>
              <CarouselPrevious />
              <CarouselNext />
            </>
          )}
        </Carousel>
      </div>
    </div>
  );
}

function HaikuCard({ haiku }: { haiku: Partial<Haiku> }) {
  return (
    <div
      data-testid="haiku-card"
      style={{ background: haiku.gradient }}
      className="relative bg-gradient-to-br from-slate-50 to-blue-50 dark:from-slate-900 dark:to-blue-950 rounded-2xl my-6 p-8 max-w-2xl border border-slate-200 dark:border-slate-700 overflow-hidden"
    >
      {/* Decorative background elements */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-gradient-to-br from-blue-400/10 to-purple-400/10 rounded-full blur-3xl -z-0" />
      <div className="absolute bottom-0 left-0 w-48 h-48 bg-gradient-to-tr from-indigo-400/10 to-pink-400/10 rounded-full blur-3xl -z-0" />

      {/* Haiku Text */}
      <div className="relative z-10 flex flex-col items-center space-y-6">
        {haiku.japanese?.map((line, index) => (
          <div
            key={index}
            className="flex flex-col items-center text-center space-y-2 animate-in fade-in slide-in-from-bottom-4"
            style={{ animationDelay: `${index * 100}ms` }}
          >
            <p
              data-testid="haiku-japanese-line"
              className="font-serif font-bold text-4xl md:text-5xl bg-gradient-to-r from-slate-800 to-slate-600 dark:from-slate-100 dark:to-slate-300 bg-clip-text text-transparent tracking-wide"
            >
              {line}
            </p>
            <p
              data-testid="haiku-english-line"
              className="font-light text-base md:text-lg text-slate-600 dark:text-slate-400 italic max-w-md"
            >
              {haiku.english?.[index]}
            </p>
          </div>
        ))}
      </div>

      {/* Image */}
      {haiku.image_name && (
        <div className="relative z-10 mt-8 pt-8 border-t border-slate-200 dark:border-slate-700">
          <div className="relative group overflow-hidden rounded-2xl shadow-xl">
            <img
              data-testid="haiku-image"
              src={`/images/${haiku.image_name}`}
              alt={haiku.image_name}
              className="object-cover w-full h-64 md:h-80 transform transition-transform duration-500 group-hover:scale-105"
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
          </div>
        </div>
      )}
    </div>
  );
}

